module shift_register(
    input reset_signal,
    input rst,
    input load,
    input [7:0] data_in,
    input shift_left,
    output reg [7:0] data_out
    );

    always @(posedge reset_signal or posedge rst) begin
        if (rst) begin
            data_out <= 8'b00000000;
        end else if (load) begin
            data_out <= data_in;
        end else if (shift_left) begin
            data_out <= data_out << 1;
        end else begin
            data_out <= data_out >> 1;
        end
    end
endmodule
